
// === IXAT PRIVATE SERVER PATCH ===
// Configurable host - change this if running on a different host/port
var IXAT_HOST = location.host || "localhost:6969";
var IXAT_PROTO = location.protocol || "http:";
var IXAT_URL = IXAT_PROTO + "//" + IXAT_HOST;

// Pre-init Module so our hooks survive the "var Module=typeof Module!="undefined"?Module:{}" below
if (typeof Module === 'undefined') var Module = {};

// === 1. WASM MEMORY PATCHING ===
// The WASM binary has "//xat.com" baked into its data section.
// After WASM memory is initialized, we search-and-replace domain strings.
Module._ixatPatchMemory = function() {
  if (typeof HEAPU8 === 'undefined') return;
  // Map of byte sequences to find -> replace in WASM linear memory
  // Replacement MUST be <= length of original (padded with nulls)
  var patches = [
    { find: '//xat.com',           replace: '//' + IXAT_HOST },
    { find: '//www.xatech.com',    replace: '//' + IXAT_HOST + '\0' },
    { find: '//i0.xat.com',        replace: '//' + IXAT_HOST },
  ];
  var patchCount = 0;
  patches.forEach(function(p) {
    var findBytes = [];
    for (var i = 0; i < p.find.length; i++) findBytes.push(p.find.charCodeAt(i));
    var replBytes = [];
    for (var i = 0; i < p.replace.length; i++) replBytes.push(p.replace.charCodeAt(i));
    // Pad replacement with nulls if shorter
    while (replBytes.length < findBytes.length) replBytes.push(0);
    // Truncate if replacement is longer (shouldn't happen - keep <= original)
    if (replBytes.length > findBytes.length) replBytes.length = findBytes.length;
    var pos = 0;
    var memLen = HEAPU8.length;
    while (pos < memLen - findBytes.length) {
      var found = true;
      for (var j = 0; j < findBytes.length; j++) {
        if (HEAPU8[pos + j] !== findBytes[j]) { found = false; break; }
      }
      if (found) {
        for (var j = 0; j < replBytes.length; j++) {
          HEAPU8[pos + j] = replBytes[j];
        }
        patchCount++;
        pos += findBytes.length; // skip past this match
      } else {
        pos++;
      }
    }
  });
  console.log('[ixat] Patched ' + patchCount + ' domain references in WASM memory');
};

// === 2. HOOK emscripten_run_script TO INTERCEPT EVAL'D CODE ===
// The WASM binary constructs JS strings with xat.com URLs and evals them.
// We hook the eval-based emscripten functions to rewrite URLs on the fly.
var _ixat_origEval = window.eval;
window.eval = function(code) {
  if (typeof code === 'string') {
    // Rewrite xat.com domain references in eval'd code
    code = code.replace(/\/\/xat\.com/g, '//' + IXAT_HOST);
    code = code.replace(/\/\/www\.xatech\.com/g, '//' + IXAT_HOST);
    code = code.replace(/\/\/i0\.xat\.com/g, '//' + IXAT_HOST);
    code = code.replace(/https:\/\/xat\.com/g, IXAT_PROTO + '//' + IXAT_HOST);
  }
  return _ixat_origEval.call(this, code);
};

// === 3. HOOK XMLHttpRequest TO REWRITE API URLS ===
// WASM's LOADURL command uses XHR - intercept and rewrite URLs
var _ixat_origXHROpen = XMLHttpRequest.prototype.open;
XMLHttpRequest.prototype.open = function(method, url, async, user, pass) {
  if (typeof url === 'string') {
    url = url.replace(/\/\/xat\.com/g, '//' + IXAT_HOST);
    url = url.replace(/\/\/www\.xatech\.com/g, '//' + IXAT_HOST);
    url = url.replace(/\/\/i0\.xat\.com/g, '//' + IXAT_HOST);
    url = url.replace(/https:\/\/xat\.com/g, IXAT_PROTO + '//' + IXAT_HOST);
  }
  return _ixat_origXHROpen.call(this, method, url, async, user, pass);
};

// === 4. HOOK fetch TO REWRITE API URLS ===
var _ixat_origFetch = window.fetch;
window.fetch = function(input, init) {
  if (typeof input === 'string') {
    input = input.replace(/\/\/xat\.com/g, '//' + IXAT_HOST);
    input = input.replace(/\/\/www\.xatech\.com/g, '//' + IXAT_HOST);
    input = input.replace(/\/\/i0\.xat\.com/g, '//' + IXAT_HOST);
    input = input.replace(/https:\/\/xat\.com/g, IXAT_PROTO + '//' + IXAT_HOST);
  }
  return _ixat_origFetch.call(this, input, init);
};

// === 5. HOOK WebSocket TO REWRITE WS URLS ===
// WASM creates WebSocket connections to wss://wss.xat.com/v2
// We intercept and redirect to our private server
var _ixat_origWebSocket = window.WebSocket;
window.WebSocket = function(url, protocols) {
  if (typeof url === 'string') {
    // Rewrite any xat.com WebSocket URLs to point to our server
    var wsProto = location.protocol === 'https:' ? 'wss:' : 'ws:';
    if (url.indexOf('xat.com') !== -1 || url.indexOf('xatech.com') !== -1) {
      var oldUrl = url;
      url = wsProto + '//' + IXAT_HOST + '/v2';
      console.log('[ixat] WebSocket redirect: ' + oldUrl + ' -> ' + url);
    }
  }
  if (protocols !== undefined) {
    return new _ixat_origWebSocket(url, protocols);
  }
  return new _ixat_origWebSocket(url);
};
window.WebSocket.prototype = _ixat_origWebSocket.prototype;
window.WebSocket.CONNECTING = _ixat_origWebSocket.CONNECTING;
window.WebSocket.OPEN = _ixat_origWebSocket.OPEN;
window.WebSocket.CLOSING = _ixat_origWebSocket.CLOSING;
window.WebSocket.CLOSED = _ixat_origWebSocket.CLOSED;

// === 6. HOOK onRuntimeInitialized TO PATCH MEMORY AFTER WASM LOADS ===
Module['onRuntimeInitialized'] = function() {
  console.log('[ixat] WASM runtime initialized, patching memory...');
  Module._ixatPatchMemory();
};

console.log('[ixat] Private server patches loaded for ' + IXAT_URL);
// === END PATCH ===

